import{j as e,L as i}from"./index-ixzp0WJG.js";/* empty css               */const t=()=>e.jsxs("div",{children:[e.jsx(i,{to:"/levels",className:"backButton level-theme-willingness",children:"Back"}),e.jsxs("div",{className:"aLevelContainer level-theme-willingness",children:[e.jsx("h1",{children:"Willingness"}),e.jsx("p",{children:"At this level, growth is rapid and success is common in all endeavors."}),e.jsx("p",{children:"Willingness implies that one has overcome inner resistance to life and is committed to participation."}),e.jsx("p",{children:"People become genuinely friendly, and social and economic successes seem to follow automatically. The willing are not troubled by unemployment; they will take any job when they have to, or create a career, or become self-employed. They do not feel demeaned by service jobs or by starting “at the bottom.”"}),e.jsx("p",{children:"Self-esteem is high and reinforced by positive feedback from society in the forms of recognition, appreciation, and reward. Willingness is sympathetic and responsive to the needs of others."}),e.jsx("p",{children:"Spiritual gratification is an unsuspected source of pleasure that brings a greater sense of well-being, which is the consequence of an increase in the flow of spiritual energy."}),e.jsx("p",{children:"There is a greater sense of aliveness and appreciation for life as its quality progressively improves. The experience is subjective, nonlinear, and subtle—but all-pervasive. Confidence and optimism replace doubt, mistrust, resistance, and cynicism. Struggle is replaced with ease."}),e.jsx("p",{children:"With relinquishment of resistance, less effort is required to function in the world. The intrinsic rewards of spiritual growth become self-activating motivation that evolves into enthusiasm as a consequence of the more positive view of self and life."}),e.jsx("p",{children:"Willingness has the extra energy that would otherwise be wasted on resistance, delay, and complaints. Willingness energises fulfilling the needs of others, and thus its social expression is benevolent and humanitarian."}),e.jsx("p",{children:"It is the level of the Golden Rule: “Do unto others as you would have others do unto you.” In successful relationships, this results in a mutuality of partners as helpmates and companions. This mutuality is the alignment with each other’s welfare rather than just the more animal-driven emotional involvement."}),e.jsx("p",{children:"Willingness is supportive rather than competitive for gain or dominance, and relationships involve service to each other’s growth and goals rather than to just one’s own."}),e.jsx("p",{children:"Willingness is harmonious and is expressed as the “win-win” attitude."})]})]});export{t as default};
